import React, { useMemo, useState, useEffect } from "react";
import axios from "axios";
import "./StubPages.css";

const API_URL = "http://localhost:5000/api";

const Billing = () => {
  const [formData, setFormData] = useState({
    patientName: "",
    consultationFee: "",
    medicineFee: "",
    labFee: "",
    paymentMethod: "UPI",
    paymentStatus: "Pending",
  });

  const [bills, setBills] = useState([]);

  // ✅ Load bills from backend
  useEffect(() => {
    fetchBills();
  }, []);

  const fetchBills = async () => {
    try {
      const res = await axios.get(`${API_URL}/bills`);
      setBills(res.data.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  // ✅ Auto total
  const totalAmount = useMemo(() => {
    return (
      (Number(formData.consultationFee) || 0) +
      (Number(formData.medicineFee) || 0) +
      (Number(formData.labFee) || 0)
    );
  }, [formData]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // ✅ Save bill to backend
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.patientName) {
      alert("Enter patient name");
      return;
    }

    try {
      await axios.post(`${API_URL}/bills`, {
        ...formData,
        totalAmount,
      });

      alert("✅ Bill Saved");
      fetchBills();

      setFormData({
        patientName: "",
        consultationFee: "",
        medicineFee: "",
        labFee: "",
        paymentMethod: "UPI",
        paymentStatus: "Pending",
      });
    } catch (err) {
      alert("Error saving bill");
    }
  };

  // ================= RAZORPAY =================
  const handleRazorpay = async (bill) => {
  try {
    const res = await axios.post(`${API_URL}/payments/create-order`, {
      amount: bill.totalAmount,
    });

    console.log("ORDER RESPONSE:", res.data);

    if (!res.data || !res.data.order) {
      alert("❌ Order creation failed");
      return;
    }

    if (!window.Razorpay) {
      alert("❌ Razorpay script not loaded");
      return;
    }

    const options = {
      key: res.data.key,
      amount: res.data.order.amount,
      currency: "INR",
      name: "HospitalHub",
      description: "Bill Payment",
      order_id: res.data.order.id,

      handler: async function (response) {
        console.log("PAYMENT SUCCESS:", response);

        await axios.post(`${API_URL}/payments/verify`, {
          ...response,
          billId: bill.billId,
        });

        alert("✅ Payment Successful");
        window.location.reload();
      },
    };

    const rzp = new window.Razorpay(options);
    rzp.open();

  } catch (err) {
    console.error("PAYMENT ERROR:", err);
    alert("❌ Payment failed (check console)");
  }
};

  // ================= PDF DOWNLOAD =================
  const downloadPDF = (bill) => {
    const html = `
      <html>
        <body>
          <h2>🏥 Hospital Invoice</h2>
          <p><b>Bill ID:</b> ${bill.billId}</p>
          <p><b>Patient:</b> ${bill.patientName}</p>

          <table border="1" cellpadding="10">
            <tr><td>Consultation</td><td>₹${bill.consultationFee}</td></tr>
            <tr><td>Medicine</td><td>₹${bill.medicineFee}</td></tr>
            <tr><td>Lab</td><td>₹${bill.labFee}</td></tr>
            <tr><td><b>Total</b></td><td><b>₹${bill.totalAmount}</b></td></tr>
          </table>

          <p>Status: ${bill.paymentStatus}</p>
        </body>
      </html>
    `;

    const win = window.open("", "", "width=800,height=600");
    win.document.write(html);
    win.document.close();
    win.print();
  };

  return (
    <div className="page">
      <h2>💰 Billing</h2>

      <div className="billing-grid">
        {/* FORM */}
        <div className="table-card">
          <h3>Create Bill</h3>

          <form onSubmit={handleSubmit}>
            <input
              name="patientName"
              placeholder="Patient Name"
              value={formData.patientName}
              onChange={handleChange}
              required
            />

            <input
              type="number"
              name="consultationFee"
              placeholder="Consultation Fee"
              value={formData.consultationFee}
              onChange={handleChange}
            />

            <input
              type="number"
              name="medicineFee"
              placeholder="Medicine Fee"
              value={formData.medicineFee}
              onChange={handleChange}
            />

            <input
              type="number"
              name="labFee"
              placeholder="Lab Fee"
              value={formData.labFee}
              onChange={handleChange}
            />

            <div>
              <b>Total: ₹{totalAmount}</b>
            </div>

            <button type="submit">Save Bill</button>
          </form>
        </div>

        {/* TABLE */}
        <div className="table-card">
          <h3>Billing Records</h3>

          <table>
            <thead>
              <tr>
                <th>Patient</th>
                <th>Total</th>
                <th>Status</th>
                <th>Pay</th>
                <th>PDF</th>
              </tr>
            </thead>

            <tbody>
              {bills.map((bill) => (
                <tr key={bill.id}>
                  <td>{bill.patientName}</td>
                  <td>₹{bill.totalAmount}</td>
                  <td>{bill.paymentStatus}</td>

                  <td>
                    {bill.paymentStatus !== "Paid" && (
                      <button onClick={() => handleRazorpay(bill)}>
                        💳 Pay
                      </button>
                    )}
                  </td>

                  <td>
                    <button onClick={() => downloadPDF(bill)}>
                      📄 PDF
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Billing;
